import boto3
import json
from botocore.exceptions import ClientError

# Define the IAM role with the necessary permissions
role = {
    "Version": "2012-10-17",
    "Statement": [
        {
            "Effect": "Allow",
            "Action": [
                "s3:GetObject",
                "s3:PutObject",
                "sns:Publish"
            ],
            "Resource": "*"
        }
    ]
}

# Define the Lambda function handler
def lambda_handler(event, context):
    # Get the S3 bucket and key from the event
    bucket = event["Records"][0]["s3"]["bucket"]["name"]
    key = event["Records"][0]["s3"]["object"]["key"]

    # Read the image from S3
    s3_client = boto3.client("s3")
    try:
        response = s3_client.get_object(Bucket=bucket, Key=key)
    except ClientError as e:
        print(e)
        return {
            "statusCode": 500,
            "body": json.dumps({"message": "Failed to read image from S3."})
        }

    # Process the image and send notifications via SNS
    sns_client = boto3.client("sns")
    try:
        response = sns_client.publish(TopicArn="YOUR_TOPIC_ARN", Message=json.dumps({"image": response["Body"].read()}))
    except ClientError as e:
        print(e)
        return {
            "statusCode": 500,
            "body": json.dumps({"message": "Failed to send notification via SNS."})
        }

    # Log the results to CloudWatch
    cloudwatch_client = boto3.client("cloudwatch")
    try:
        response = cloudwatch_client.put_metric_data(MetricData=[{"MetricName": "ImageProcessing", "Value": 1}])
    except ClientError as e:
        print(e)
        return {
            "statusCode": 500,
            "body": json.dumps({"message": "Failed to log results to CloudWatch."})
        }

    # Return a successful response
    return {
        "statusCode": 200,
        "body": json.dumps({"message": "Image processed successfully."})
    }